#include <iostream>
#include <vector>
using namespace std;
int maxPoints(vector<vector<int>>& points) {
    int n = points.size();
    int maxPoints = 0;
    for (int i = 0; i < n; i++) {
        unordered_map<double, int> count;
        int same = 1;
        for (int j = i + 1; j < n; j++) {
            if (points[i] == points[j]) same++;
            else {
                double slope = (double)(points[j][1] - points[i][1]) / (points[j][0] - points[i][0]);
                count[slope]++;
            }
        }
        maxPoints = max(maxPoints, (count.empty() ? 0 : *max_element(count.begin(), count.end(), [](auto& a, auto& b) {return a.second < b.second;})) + same);
    }
    return maxPoints;
}

