import java.util.HashMap;
import java.util.Map;
public class Solution {
    public int maxPoints(int[][] points) {
        int n = points.length;
        int max = 0;
        for (int i = 0; i < n; i++) {
            Map<Double, Integer> count = new HashMap<>();
            int same = 1;
            for (int j = i + 1; j < n; j++) {
                if (points[i][0] == points[j][0] && points[i][1] == points[j][1]) same++;
                else {
                    double slope = (double)(points[j][1] - points[i][1]) / (points[j][0] - points[i][0]);
                    count.put(slope, count.getOrDefault(slope, 0) + 1);
                }
            }
            max = Math.max(max, count.values().stream().max(Integer::compare).orElse(0) + same);
        }
        return max;
    }
}

